$("scene-add-enemy").onclick=()=>{const profile=enemyProfile($("scene-enemy-select").value);if(!profile)return toast("Выберите профиль врага");const tier=clamp($("scene-enemy-tier").value,1,99),stats=scaledEnemyStats(profile,tier),position=firstEmptyCell(Scene.activeSpace),effectIds=(profile.deployEffects||[]).map(name=>D.effects.positive.concat(D.effects.negative).find(effect=>effect.name===name)?.id||name);commitScene(`Добавлен враг «${profile.name}» Ст.${tier}`,scene=>{const actor={id:uid(),kind:"enemy",team:"enemy",heroId:null,profileId:profile.id,name:profile.name,tier,space:scene.activeSpace,...position,hp:stats.health,maxHp:stats.health,ap:2,baseAp:2,speed:stats.speed,armor:stats.armor,evasion:stats.evasion,effects:effectIds,usedActions:[],usedTrump:false,acted:false,hidden:false,tokenSymbol:"☠",tokenColor:"#902a3d",tokenImage:"",portraitImage:""};scene.actors.push(actor);scene.selectedActor=actor.id})};
$("scene-add-free-token").onclick=()=>{const name=$("scene-free-token-name").value.trim()||"Свободный токен",team=$("scene-free-token-team").value==="enemy"?"enemy":"hero",position=firstEmptyCell(Scene.activeSpace);commitScene(`Добавлен токен «${name}»`,scene=>{const actor={id:uid(),kind:"token",team,heroId:null,profileId:null,name:name.slice(0,120),tier:1,space:scene.activeSpace,...position,hp:1,maxHp:1,speed:0,armor:0,evasion:0,effects:[],acted:false,hidden:false,tokenSymbol:team==="enemy"?"☠":"✦",tokenColor:team==="enemy"?"#902a3d":"#256a92",tokenImage:"",portraitImage:""};scene.actors.push(actor);scene.selectedActor=actor.id});$("scene-free-token-name").value=""};
$("scene-add-space").onclick=()=>{const name=$("scene-space-name").value.trim()||`Отдельное пространство ${Scene.spaces.length}`;commitScene(`Создано пространство «${name}»`,scene=>{const space={id:uid(),name,width:7,height:7};scene.spaces.push(space);scene.activeSpace=space.id;scene.selectedActor=null;scene.targetIds=[]});$("scene-space-name").value=""};
$("scene-clear-log").onclick=()=>{Scene.log=[];persist();renderScene()};
$("scene-inspector").addEventListener("change",async event=>{
  const actorId=event.target.dataset.sceneActorName||event.target.dataset.sceneActorHp||event.target.dataset.sceneActorSpace||event.target.dataset.sceneActorActed||event.target.dataset.sceneTokenSymbol||event.target.dataset.sceneTokenColor||event.target.dataset.sceneTokenUpload,actor=Scene.actors.find(item=>item.id===actorId);if(!actor)return;
  if(event.target.dataset.sceneActorName)commitScene(`Переименован участник «${actor.name}»`,()=>{actor.name=event.target.value.trim().slice(0,120)||actor.name});
  else if(event.target.dataset.sceneActorHp)commitScene(`Здоровье «${actor.name}»: ${actor.hp} → ${clamp(event.target.value,0,9999)}`,()=>{actor.hp=clamp(event.target.value,0,9999)});
  else if(event.target.dataset.sceneActorSpace){const targetSpace=event.target.value,position=firstEmptyCell(targetSpace),spaceName=Scene.spaces.find(space=>space.id===targetSpace)?.name||"пространство";commitScene(`«${actor.name}» перенесён: ${spaceName}`,()=>{actor.space=targetSpace;actor.x=position.x;actor.y=position.y;Scene.activeSpace=targetSpace})}
  else if(event.target.dataset.sceneActorActed)commitScene(`${actor.name}: ${event.target.checked?"Ход завершён":"Ход возвращён"}`,()=>{actor.acted=event.target.checked});
  else if(event.target.dataset.sceneTokenSymbol)commitScene(`Изменён знак токена «${actor.name}»`,()=>{actor.tokenSymbol=event.target.value.slice(0,4);actor.tokenImage=""});
  else if(event.target.dataset.sceneTokenColor)commitScene(`Изменён цвет токена «${actor.name}»`,()=>{actor.tokenColor=safeColor(event.target.value,actor.tokenColor)});
  else if(event.target.dataset.sceneTokenUpload){try{const image=await tokenImageFromFile(event.target.files?.[0]),current=Scene.actors.find(item=>item.id===actorId);if(sceneMediaSize()-(current?.tokenImage?.length||0)+image.length>1850000)throw new Error("Медиа общего стола превышают 1,85 МБ; замените или удалите старое изображение");if(current)commitScene(`Загружено изображение токена «${current.name}»`,()=>{current.tokenImage=image})}catch(error){toast(error.message||"Не удалось загрузить токен")}}
});
$("scene-inspector").addEventListener("click",event=>{const turn=event.target.closest("[data-scene-turn]"),removeActor=event.target.closest("[data-scene-remove-actor]"),removeObject=event.target.closest("[data-scene-remove-object]"),removeMarker=event.target.closest("[data-scene-remove-marker]"),clearToken=event.target.closest("[data-scene-clear-token-image]"),effect=event.target.closest("[data-scene-actor-effect]");if(turn){const actor=Scene.actors.find(item=>item.id===turn.dataset.sceneActorId);if(actor){const start=turn.dataset.sceneTurn==="start";commitSceneEvents(`${actor.name}: ${start?"начат":"завершён"} Ход`,[{type:start?"turn.start":"turn.end",actorId:actor.id,payload:{}}])}return}if(removeActor){const actor=Scene.actors.find(item=>item.id===removeActor.dataset.sceneRemoveActor);if(actor)commitScene(`Убран участник «${actor.name}»`,scene=>{scene.actors=scene.actors.filter(item=>item.id!==actor.id);scene.targetIds=scene.targetIds.filter(id=>id!==actor.id);scene.selectedActor=null;if(scene.activeActorId===actor.id)scene.activeActorId=null});return}if(removeObject){const object=Scene.objects.find(item=>item.id===removeObject.dataset.sceneRemoveObject);if(object)commitScene(`Удалена область «${object.label}»`,scene=>{scene.objects=scene.objects.filter(item=>item.id!==object.id)});return}if(removeMarker){const marker=Scene.markers.find(item=>item.id===removeMarker.dataset.sceneRemoveMarker);if(marker)commitScene(`Удалён маркер «${marker.label}»`,scene=>{scene.markers=scene.markers.filter(item=>item.id!==marker.id)});return}if(clearToken){const actor=Scene.actors.find(item=>item.id===clearToken.dataset.sceneClearTokenImage);if(actor)commitScene(`Удалено изображение токена «${actor.name}»`,()=>{actor.tokenImage=""});return}if(effect){const actor=Scene.actors.find(item=>item.id===effect.dataset.sceneActorEffect),id=effect.dataset.effect;if(actor)commitScene(`${actor.name}: ${actor.effects.includes(id)?"снят":"наложен"} Эффект`,()=>{actor.effects=actor.effects.includes(id)?actor.effects.filter(item=>item!==id):actor.effects.concat(id)})}});
$("scene-inspector").addEventListener("click",event=>{const panel=event.target.closest("[data-open-scene-panel]");if(panel)setScenePanel(panel.dataset.openScenePanel)});
$("scene-inspector").addEventListener("change",async event=>{const actorId=event.target.dataset.scenePortraitUpload;if(!actorId)return;try{const image=await imageFromFile(event.target.files?.[0],{maxSide:720,maxLength:420000}),actor=Scene.actors.find(item=>item.id===actorId);if(!actor)return;if(sceneMediaSize()-(actor.portraitImage?.length||0)+image.length>1850000)throw new Error("Медиа общего стола превышают 1,85 МБ; удалите старый арт или портрет");commitScene(`Загружен портрет «${actor.name}»`,()=>{actor.portraitImage=image})}catch(error){toast(error.message||"Не удалось загрузить портрет")}});
$("scene-inspector").addEventListener("click",event=>{const button=event.target.closest("[data-scene-clear-portrait-image]");if(!button)return;const actor=Scene.actors.find(item=>item.id===button.dataset.sceneClearPortraitImage);if(actor)commitScene(`Удалён портрет «${actor.name}»`,()=>{actor.portraitImage=""})});
$("scene-media-menu").addEventListener("click",event=>{const portrait=event.target.closest("[data-scene-portrait-actor]");if(portrait){const actor=Scene.actors.find(item=>item.id===portrait.dataset.scenePortraitActor);if(actor){Scene.activeSpace=actor.space;Scene.selectedActor=actor.id;persist();renderScene()}return}const button=event.target.closest("[data-scene-art-action]");if(!button)return;const art=Scene.artworks.find(item=>item.id===button.dataset.sceneArtId);if(!art)return;const action=button.dataset.sceneArtAction;if(action==="remove")commitScene(`Удалён арт «${art.name}»`,scene=>{scene.artworks=scene.artworks.filter(item=>item.id!==art.id);if(scene.featuredArt===art.id)scene.featuredArt=null;if(scene.backgroundArt===art.id)scene.backgroundArt=null});else if(action==="feature")commitScene(`${Scene.featuredArt===art.id?"Скрыт":"Показан"} арт «${art.name}»`,scene=>{scene.featuredArt=scene.featuredArt===art.id?null:art.id});else if(action==="background")commitScene(`${Scene.backgroundArt===art.id?"Снят фон":"Установлен фон"} «${art.name}»`,scene=>{scene.backgroundArt=scene.backgroundArt===art.id?null:art.id})});
$("scene-art-upload").addEventListener("change",async event=>{try{if(Scene.artworks.length>=12)throw new Error("В Сцене можно хранить не больше 12 артов");const image=await imageFromFile(event.target.files?.[0],{maxSide:960,maxLength:520000});if(sceneMediaSize()+image.length>1850000)throw new Error("Медиа общего стола превышают 1,85 МБ; удалите старый арт или портрет");const name=$("scene-art-name").value.trim()||"Арт Сцены",kind=$("scene-art-kind").value==="background"?"background":"art";commitScene(`Загружен арт «${name}»`,scene=>{const art={id:uid(),name:name.slice(0,120),kind,image,hidden:false};scene.artworks.push(art);if(kind==="background")scene.backgroundArt=art.id;else scene.featuredArt=art.id});$("scene-art-name").value=""}catch(error){toast(error.message||"Не удалось загрузить арт")}event.target.value=""});

function setPlayCounter(key,value){
  value=Math.max(0,Number(value)||0);if(key==="stress")value=Math.min(3,value);const actor=currentHeroActor(),sync=Sync?.state(),actorKeys=new Set(["hp","wounds","focus","influence","ap"]);
  if(sync?.sceneId&&sync.role==="player"&&key==="tension")return toast("Общее Напряжение меняет Нарратор");
  if(actor&&actorKeys.has(key)){if(sync?.sceneId&&sync.role==="player"){actor[key]=value;S.runtime[key]=value;persist();renderPlay();Sync.submitCommand("update_runtime",{actorId:actor.id,key,value}).catch(error=>toast(error.message||"Изменение не отправлено Нарратору"));return}commitScene(`${actor.name}: ${key} → ${value}`,()=>{actor[key]=value});renderPlay();return}
  S.runtime[key]=value;persist();renderPlay();
}
$("play-counters").addEventListener("click",event=>{const b=event.target.closest("[data-counter]");if(!b)return;const key=b.dataset.counter;setPlayCounter(key,(+S.runtime[key]||0)+(+b.dataset.delta))});
$("play-counters").addEventListener("change",event=>{const key=event.target.dataset.counterInput;if(key)setPlayCounter(key,event.target.value)});
$("new-round").onclick=()=>{commitSceneEvents(`Завершён Раунд ${Scene.round}`,[{type:"round.end",actorId:null,payload:{}}]);toast("Раунд завершён: Напряжение +1, ОД восстановлены")};
$("new-scene").onclick=()=>{const d=derived();S.runtime.hp=d.hp;S.runtime.focus=d.focus;S.runtime.ap=3;S.runtime.tension=0;S.runtime.effects=[];commitScene("Начата новая Сцена",scene=>{scene.round=1;scene.tension=0;scene.activeActorId=null;scene.targetIds=[];scene.pendingAction=null;scene.actors.forEach(actor=>{actor.acted=false;actor.ap=actor.baseAp||3;actor.usedActions=[];actor.usedTrump=false});scene.objects=scene.objects.filter(object=>object.duration==="persistent");scene.markers=scene.markers.filter(marker=>marker.duration==="persistent")});renderPlay()};
function takeWound(external){const actor=currentHeroActor();if(actor){commitSceneEvents(external?"Рана от внешнего источника":"Рана от себя",[{type:"damage.apply",actorId:external?null:actor.id,payload:{targetId:actor.id,amount:Math.max(1,actor.hp),ignoreArmor:true}}]);return}const d=derived();S.runtime.wounds++;S.runtime.hp=d.guts;if(external)S.runtime.influence++;persist();renderPlay();}
$("wound-external").onclick=()=>takeWound(true);$("wound-self").onclick=()=>takeWound(false);$("intermission").onclick=()=>{S.runtime.wounds=0;S.runtime.stress=0;persist();renderPlay();};
$("scene-notes").addEventListener("input",e=>{S.runtime.notes=e.target.value;persist();});
$("effect-tracker").addEventListener("click",event=>{const b=event.target.closest("[data-effect]");if(!b)return;const id=b.dataset.effect;S.runtime.effects=S.runtime.effects.includes(id)?S.runtime.effects.filter(x=>x!==id):S.runtime.effects.concat(id);persist();renderPlay();});
$("play-kit").addEventListener("click",event=>{const button=event.target.closest("[data-sacrifice]");if(!button)return;const id=button.dataset.sacrifice;if(S.runtime.sacrifices.includes(id))return toast("По правилу Жертвы эту цену нельзя восстановить — только заменить");S.runtime.sacrifices.push(id);persist();renderPlay()});
$("play-kit").addEventListener("click",event=>{
  const joinButton=event.target.closest("[data-core-join-hero]"),actionButton=event.target.closest("[data-core-action]"),reactionButton=event.target.closest("[data-core-reaction]"),techniqueButton=event.target.closest("[data-core-technique]"),assistButton=event.target.closest("[data-core-assist-technique]"),manualButton=event.target.closest("[data-core-manual-technique]");
  if(joinButton){runSyncAction(async()=>{const character=await Sync.saveCharacter(S);await Sync.submitCommand("join_hero",{characterId:character.id})},"Лист отправлен Нарратору");return}
  if(techniqueButton){startTechnique(techniqueButton.dataset.coreTechnique);return}
  if(assistButton){const actor=currentHeroActor(),entry=TechniqueEngine.techniqueCoverage(D,actor?.techniques||{}).find(item=>item.id===assistButton.dataset.coreAssistTechnique),effectIds=(entry?.mechanics?.directEffects||[]).map(name=>D.effects.positive.concat(D.effects.negative).find(effect=>effect.name===name)?.id).filter(Boolean);if(effectIds.length&&!Scene.targetIds.length){Scene.tool="target";setScenePanel(null);renderScene();toast(`«${entry.name}»: отметьте цели Эффекта на поле и снова откройте Технику`);return}const prepared=TechniqueEngine.assistedPreview(Scene,{actorId:actor?.id,entry,targetIds:[...Scene.targetIds],effectIds,note:"Сложные условия подтверждает Нарратор"});if(!prepared.ok)return toast(prepared.errors.join(" "));commitTechniquePreview(prepared);return}
  if(manualButton){const actor=currentHeroActor(),entry=TechniqueEngine.techniqueCoverage(D,actor?.techniques||{}).find(item=>item.id===manualButton.dataset.coreManualTechnique),prepared=TechniqueEngine.manualPreview(Scene,{actorId:actor?.id,entry,targetIds:[...Scene.targetIds],note:"Механический итог подтверждает Нарратор"});if(!prepared.ok)return toast(prepared.errors.join(" "));commitTechniquePreview(prepared);return}
  if(actionButton){const action=D.actions.list.find(item=>item.id===actionButton.dataset.coreAction);if(!action)return;if(["Шаг","Прыжок"].includes(action.name)){pendingCoreAction=action.id;Scene.tool="select";setScenePanel(null);renderScene();toast(`«${action.name}»: выберите свободную клетку на поле`)}else prepareCoreAction(action.id);return}
  if(reactionButton){const actorId=reactionButton.dataset.coreReactionActor,choice=reactionButton.dataset.coreReaction,option=SceneEngine.reactionOptions(Scene,D,actorId).find(item=>item.id===choice);if(option?.name==="Уворот"){pendingCoreReaction={actorId,choice};setScenePanel(null);toast("Уворот: выберите свободную клетку в пределах 2 клеток");return}const prepared=SceneEngine.respondReaction(Scene,D,{actorId,choice});if(!prepared.ok)return toast(prepared.errors.join(" "));commitSceneEvents(option?.name||"Реакция",prepared.events);return}
  if(event.target.closest("[data-core-resolve]")){const prepared=SceneEngine.resolvePendingAction(Scene,D);if(!prepared.ok)return toast(prepared.errors.join(" "));commitSceneEvents("Атака разрешена",prepared.events)}
});
$("play-kit").addEventListener("click",event=>{const tab=event.target.closest("[data-sheet-tab]"),panel=event.target.closest("[data-open-scene-panel]"),mode=event.target.closest("[data-open-mode]"),wound=event.target.closest("[data-scene-wound]");if(tab){setSheetTab(tab.dataset.sheetTab);return}if(panel){setScenePanel(panel.dataset.openScenePanel);return}if(mode){setScenePanel(null);setMode(mode.dataset.openMode);return}if(wound)takeWound(wound.dataset.sceneWound==="external")});
